import{_ as e,o as s,c as o,g as t}from"./chunks/framework.CtuiYkcd.js";const B=JSON.parse('{"title":"魔方·对称性","description":"","frontmatter":{"title":"魔方·对称性","date":"2015-08-23T13:38:27.928Z","length":"243字","time":"1分钟","aside":false,"hash":-1145495729},"headers":[],"relativePath":"article/魔方·对称性.md","filePath":"article/魔方·对称性.md"}'),_={name:"article/魔方·对称性.md"},a=t("p",null,"近来迷上了魔方。",-1),n=t("p",null,"很快就学会了复原，毕竟只是单纯背公式。可我不知道原理，心中甚为郁结。",-1),l=t("p",null,"魔方是一种对称性的浓缩、下载，充满奇趣和魔力，但是没有群论，我无法驾驭这种对称性。",-1),c=t("p",null,"对称意味着在施加操作的情况下保持不变，这个不变量与对称操作是紧密相关的，而这操作便也预示着一种对称性。",-1),i=t("p",null,"对称需要从不对称处欣赏，复原魔方最快的方法是什么？把它扔到一个黑暗处，颜色不再显现，于是无论怎么看，魔方都是一致的。颜色不加区分便造成了这种对称性。因而最高级的对称便是虚空。然而这是我们无法观察的，只有颜色的分化、感觉的分化，我们才可以考知这种对称。",-1),r=t("p",null,"这是无中生有的道理。",-1),d=[a,n,l,c,i,r];function p(h,u,m,f,$,g){return s(),o("div",null,d)}const k=e(_,[["render",p]]);export{B as __pageData,k as default};
